import { useEffect, useState } from "react";
import homeImages from "../data/homeImages.json";
import { getProducts } from "../services/productService";
import { BannerCarousel, List } from "../components/organisms";
import { ErrorMessage, Loading, Button } from "../components/atoms";

export default function Home() {
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [page] = useState(1);
  const [display, setDisplay] = useState("grid");

  useEffect(() => {
    const loadProducts = async () => {
      try {
        setLoading(true);
        setError(null);
        const productsData = await getProducts();
        console.log("productsData:", productsData);
        // Robust fallback if productsData or productsData.products is undefined
        setProducts(productsData?.products || Array.isArray(productsData) ? productsData : []);
      } catch (err) {
        setError("No se pudieron cargar los productos. Intenta más tarde.");
        setProducts([]);
      } finally {
        setLoading(false);
      }
    };

    loadProducts();
  }, [page]);

  const toggleDisplay = () => {
    // if (display ==="grid") {
    //   setDisplay("list-vertical");
    // }else{
    //   setDisplay('grid');
    // }

    display === "grid" ? setDisplay("list-vertical") : setDisplay("grid");
  };

  return (
    <div>
      <BannerCarousel banners={homeImages} />
      {loading ? (
        <Loading>Cargando productos...</Loading>
      ) : error ? (
        <ErrorMessage>{error}</ErrorMessage>
      ) : (products || []).length > 0 ? (
        <div>
          <Button onClick={toggleDisplay}>{display}</Button>
          <List
            title="Productos recomendados"
            products={products || []}
            layout={display}
          />
        </div>
      ) : (
        <ErrorMessage>No hay productos en el catálogo</ErrorMessage>
      )}
    </div>
  );
}
